const DEFAULT_API_BASE="http://localhost:3000";function getApiBase(){return new Promise(e=>{chrome.storage.local.get(["apiBase"],t=>{const o="string"==typeof t.apiBase?t.apiBase.trim():"";e(o||DEFAULT_API_BASE)})})}function isLikelyUrl(e){try{const t=new URL(e);return"http:"===t.protocol||"https:"===t.protocol}catch{return!1}}async function saveUrlToApp(e){const t=await getApiBase(),o=await fetch(`${t}/api/links`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({url:e})});if(!o.ok){const e=await o.json().catch(()=>({}));throw new Error(e?.error||`Save failed (${o.status})`)}return t}chrome.omnibox.onInputStarted.addListener(()=>{chrome.omnibox.setDefaultSuggestion({description:"Linksavekren: type a URL to <match>save & open</match>, or type <match>open</match>."})}),chrome.omnibox.onInputChanged.addListener((e,t)=>{const o=e.trim();t([{content:o||"open",description:o?`Save and open: <match>${o}</match>`:"Open Linksavekren app"},{content:"open",description:"Open Linksavekren app only"}])}),chrome.omnibox.onInputEntered.addListener(async e=>{const t=e.trim(),o=await getApiBase();if(t&&"open"!==t.toLowerCase())if(isLikelyUrl(t))try{const e=await saveUrlToApp(t);await chrome.tabs.create({url:e})}catch(e){const t=e instanceof Error?encodeURIComponent(e.message):"save_failed";await chrome.tabs.create({url:`${o}?error=${t}`})}else await chrome.tabs.create({url:o});else await chrome.tabs.create({url:o})});